// ---------------------------------------------------------------------------
// dynamic_chain_costs — fallback chain + clamp boundaries.
// ---------------------------------------------------------------------------

#[test]
fn dynamic_chain_costs_generator_cases_replay_exactly() {
    let fx = floors_fixture("dynamic_chain_costs");
    for case in fx["cases"].as_array().unwrap() {
        let name = case["name"].as_str().unwrap();
        let perkb = &case["perkb"];
        let expected = &case["expected"];

        let actual = dynamic_chain_costs(perkb);
        if expected.is_null() {
            assert!(actual.is_none(), "{name}: expected None");
            continue;
        }
        let actual = actual.unwrap_or_else(|| panic!("{name}: expected Some"));
        assert_eq!(
            actual.open_cost_sats,
            expected["open_cost_sats"].as_i64().unwrap(),
            "{name}: open_cost_sats"
        );
        assert_eq!(
            actual.close_cost_sats,
            expected["close_cost_sats"].as_i64().unwrap(),
            "{name}: close_cost_sats"
        );
        assert_eq!(
            py_repr(actual.sat_per_vbyte),
            expected["sat_per_vbyte"].as_str().unwrap(),
            "{name}: sat_per_vbyte"
        );
    }
}

// ---------------------------------------------------------------------------
// rebalance_cost_floor — integer-division pin, confidence gating, window
// re-filtering.
// ---------------------------------------------------------------------------

#[test]
fn rebalance_cost_floor_generator_cases_replay_exactly() {
    let fx = floors_fixture("rebalance_cost_floor");
    let now = fx["now"].as_i64().unwrap();
    for case in fx["cases"].as_array().unwrap() {
        let name = case["name"].as_str().unwrap();
        let flow_state = case["flow_state"].as_str().unwrap();
        let recent_costs: Vec<RebalanceCostSample> = case["recent_costs"]
            .as_array()
            .unwrap()
            .iter()
            .map(|c| RebalanceCostSample {
                cost_sats: c["cost_sats"].as_i64().unwrap(),
                amount_sats: c["amount_sats"].as_i64().unwrap(),
                timestamp: c["timestamp"].as_i64().unwrap(),
            })
            .collect();
        let peer_fallback = &case["peer_fallback"];
        let confidence = peer_fallback.get("confidence").and_then(|v| v.as_str());
        let avg_fee_ppm = peer_fallback.get("avg_fee_ppm").and_then(|v| v.as_i64());
        let peer_fallback_opt = match (confidence, avg_fee_ppm) {
            (Some(c), Some(a)) => Some((c, a)),
            _ => None,
        };

        let actual = rebalance_cost_floor(flow_state, &recent_costs, peer_fallback_opt, now);
        let expected = case["expected"].as_i64();
        assert_eq!(actual, expected, "{name}");
    }
}

