// ---------------------------------------------------------------------------
// detect_congestion — live-vs-snapshot resolution, staleness TTL.
// ---------------------------------------------------------------------------

fn parse_flow_state_row(v: &Value) -> Option<FlowStateRow> {
    if v.is_null() {
        return None;
    }
    Some(FlowStateRow {
        state: v.get("state").and_then(|x| x.as_str()).map(String::from),
        updated_at: v.get("updated_at").and_then(|x| x.as_i64()),
    })
}

fn parse_live_htlc(v: &Value) -> Option<LiveHtlc> {
    if v.is_null() {
        return None;
    }
    Some(LiveHtlc {
        has_htlc_data: v["has_htlc_data"].as_bool().unwrap(),
        max_accepted_htlcs: v["max_accepted_htlcs"].as_i64().unwrap(),
        our_htlcs_in_flight: v["our_htlcs_in_flight"].as_i64().unwrap(),
    })
}

#[test]
fn detect_congestion_generator_cases_replay_exactly() {
    let fx = floors_fixture("congestion");
    for case in fx["cases"].as_array().unwrap() {
        let name = case["name"].as_str().unwrap();
        let state = parse_flow_state_row(&case["state"]);
        let channel_info = parse_live_htlc(&case["channel_info"]);
        let threshold: f64 = case["htlc_congestion_threshold"]
            .as_str()
            .unwrap()
            .parse()
            .unwrap();
        let flow_interval = case["flow_interval"].as_i64().unwrap();
        let now = case["now"].as_i64().unwrap();

        let actual = detect_congestion(
            state.as_ref(),
            channel_info.as_ref(),
            threshold,
            flow_interval,
            now,
        );
        assert_eq!(actual, case["expected"].as_bool().unwrap(), "{name}");
    }
}

// ---------------------------------------------------------------------------
// effective_min_fee_ppm / is_flow_balanced_router — class-aware min fee.
// ---------------------------------------------------------------------------

#[test]
fn effective_min_fee_generator_cases_replay_exactly() {
    let fx = floors_fixture("effective_min_fee");
    for case in fx["cases"].as_array().unwrap() {
        let name = case["name"].as_str().unwrap();
        let cfg = MinFeeCfg {
            min_fee_ppm: case["min_fee_ppm"].as_i64().unwrap(),
            min_fee_ppm_saturated: case["min_fee_ppm_saturated"].as_i64().unwrap(),
        };
        let flow_state = case["flow_state"].as_str();
        let outbound_ratio = case["outbound_ratio"]
            .as_str()
            .map(|s| s.parse::<f64>().unwrap());
        let capacity_sats = case["capacity_sats"].as_i64().unwrap();
        let flow_window = case["flow_window"].as_array().map(|arr| FlowWindow {
            out_sats: arr[0].as_i64().unwrap(),
            in_sats: arr[1].as_i64().unwrap(),
        });

        let actual = effective_min_fee_ppm(
            &cfg,
            flow_state,
            outbound_ratio,
            capacity_sats,
            flow_window.as_ref(),
        );
        assert_eq!(actual, case["expected"].as_i64().unwrap(), "{name}");
    }
}

#[test]
fn is_flow_balanced_router_boundary_cases() {
    // capacity <= 0 -> false regardless of window.
    assert!(!is_flow_balanced_router(
        0,
        Some(&FlowWindow {
            out_sats: 100,
            in_sats: 100
        })
    ));
    // No window data -> false.
    assert!(!is_flow_balanced_router(1_000_000, None));
    // gross == 0 -> false.
    assert!(!is_flow_balanced_router(
        1_000_000,
        Some(&FlowWindow {
            out_sats: 0,
            in_sats: 0
        })
    ));
    // Exactly at the minimum weekly turnover boundary AND at the max net
    // ratio boundary (both `<=`/inclusive per py 2806/2809): balanced.
    // gross = capacity * 0.25 = 250_000; net_ratio = 0.33 exactly.
    let out = 166_250i64; // (gross + net*gross)/2 with net=0.33, gross=250_000
    let in_ = 250_000 - out;
    assert!(is_flow_balanced_router(
        1_000_000,
        Some(&FlowWindow {
            out_sats: out,
            in_sats: in_
        })
    ));
}
